import { isUndefined } from 'lodash-es';
import {
  Children,
  isValidElement,
  type JSXElementConstructor,
  type ReactElement,
  type ReactNode,
} from 'react';
import { isElement } from 'react-is';

import { isSlot } from './is-slot.js';
import { BubbleLayer as MapBubbleLayer } from '../components/BubbleLayer/BubbleLayer.js';
import { ChoroplethLayer as MapChoroplethLayer } from '../components/ChoroplethLayer/ChoroplethLayer.js';
import { ConnectionLayer as MapConnectionLayer } from '../components/ConnectionLayer/ConnectionLayer.js';
import { DotLayer as MapDotLayer } from '../components/DotLayer/DotLayer.js';
import { BubbleLayer } from '../slots/BubbleLayer.js';
import { ChoroplethLayer } from '../slots/ChoroplethLayer.js';
import { ConnectionLayer } from '../slots/ConnectionLayer.js';
import { DotLayer } from '../slots/DotLayer.js';
import type { LegendColorLayerProps } from '../types/coloring.js';
import type { Location } from '../types/location.js';

// TODO: React 19 update
// eslint-disable-next-line @typescript-eslint/no-explicit-any
const sanitizeData = (child: ReactElement<any>, key: string) => {
  return child.props.data.filter((datapoint: Location) => {
    const value = datapoint[key as keyof Location];
    return !(value === null || isUndefined(value));
  });
};

const layers = new WeakMap<JSXElementConstructor<never>, { prefix: string }>([
  [BubbleLayer, { prefix: 'bubble' }],
  [DotLayer, { prefix: 'dot' }],
  [ChoroplethLayer, { prefix: 'choropleth' }],
  [ConnectionLayer, { prefix: 'connection' }],
]);

const isValidLayer = (child: ReactNode): boolean => {
  if (!isElement(child) || typeof child.type === 'string') {
    return false;
  }
  const componentType = child.type as JSXElementConstructor<never>;
  return (
    layers.get(componentType) !== undefined &&
    (isSlot(child, BubbleLayer) ||
      isSlot(child, ConnectionLayer) ||
      isSlot(child, ChoroplethLayer) ||
      isSlot(child, DotLayer))
  );
};

// eslint-disable-next-line @typescript-eslint/no-explicit-any
const createLayer = (child: ReactElement, data: any, layerId: string) => {
  if (isSlot(child, BubbleLayer)) {
    return <MapBubbleLayer {...child.props} data={data} layerId={layerId} />;
  }
  if (isSlot(child, ConnectionLayer)) {
    return (
      <MapConnectionLayer {...child.props} data={data} layerId={layerId} />
    );
  }
  if (isSlot(child, DotLayer)) {
    return <MapDotLayer {...child.props} data={data} layerId={layerId} />;
  }
  if (isSlot(child, ChoroplethLayer)) {
    return (
      <MapChoroplethLayer {...child.props} data={data} layerId={layerId} />
    );
  }
  return child;
};

/**
 * Set layers id to layer slots provided by the consumer.
 * @param children - MapView children
 * @returns An array with all the layers IDs and the children using the layer component
 */
export const setLayersId = (
  children: ReactNode,
): {
  layerIds: string[];
  parsedChildren: ReactNode;
  valueAccessors: Map<string, string>;
} => {
  const layerIds: string[] = [];
  let index = 0;
  const valueAccessors = new Map<string, string>();

  const parsedChildren = Children.map(children, (child) => {
    if (!isValidLayer(child)) {
      return child;
    }

    const validChild = child as ReactElement;
    const componentType = validChild.type as JSXElementConstructor<never>;
    const layer = layers.get(componentType);
    const layerId = `${layer?.prefix}-${index}`;

    if (
      isValidElement<LegendColorLayerProps>(validChild) &&
      validChild.props.color === 'legend' &&
      validChild.props.valueAccessor
    ) {
      valueAccessors.set(layerId, validChild.props.valueAccessor);
    }

    index += 1;
    layerIds.push(layerId);

    const layerIdValueAccessor = valueAccessors.get(layerId);
    const data = layerIdValueAccessor
      ? sanitizeData(validChild, layerIdValueAccessor)
      : validChild.props.data;

    return createLayer(validChild, data, layerId);
  });

  return { layerIds, parsedChildren, valueAccessors };
};
